import React, { useState, useEffect } from 'react';
import {
  Box,
  Container,
  Typography,
  Grid,
  Paper,
  Card,
  CardContent,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Button,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  IconButton,
  Alert,
  Chip,
  Tabs,
  Tab,
  Avatar,
  Tooltip,
} from '@mui/material';
import {
  People as PeopleIcon,
  Event as EventIcon,
  AccessTime as TimeIcon,
  Close as CloseIcon,
  CheckCircle as CheckCircleIcon,
  Cancel as CancelIcon,
  CalendarToday,
  AccessTime,
  Person,
  LocalHospital,
  Edit,
  Assignment,
  Search,
} from '@mui/icons-material';
import { useAuth } from '../../context/AuthContext';
import axios from 'axios';
import { format } from 'date-fns';

const Dashboard = () => {
  const { user } = useAuth();
  const [stats, setStats] = useState({
    totalPatients: 0,
    todayAppointments: 0,
    pendingAppointments: 0,
    completedAppointments: 0,
  });
  const [appointments, setAppointments] = useState([]);
  const [selectedAppointment, setSelectedAppointment] = useState(null);
  const [openPrescriptionDialog, setOpenPrescriptionDialog] = useState(false);
  const [prescriptionNote, setPrescriptionNote] = useState('');
  const [activeTab, setActiveTab] = useState(0);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (user?._id) {
      fetchDashboardData();
    }
  }, [user]);

  const fetchDashboardData = async () => {
    try {
      setLoading(true);
      setError('');

      const [appointmentsRes, statsRes] = await Promise.all([
        axios.get(`http://localhost:5000/api/appointments/doctor/${user._id}`),
        axios.get(`http://localhost:5000/api/doctors/${user._id}/stats`),
      ]);

      setAppointments(appointmentsRes.data);
      setStats(statsRes.data);
      setSuccess('Data loaded successfully');
    } catch (error) {
      console.error('Error fetching dashboard data:', error);
      setError(error.response?.data?.message || 'Failed to fetch dashboard data');
    } finally {
      setLoading(false);
    }
  };

  const handleTabChange = (event, newValue) => {
    setActiveTab(newValue);
  };

  const handleOpenPrescription = (appointment) => {
    setSelectedAppointment(appointment);
    setPrescriptionNote('');
    setOpenPrescriptionDialog(true);
  };

  const handleClosePrescription = () => {
    setOpenPrescriptionDialog(false);
    setSelectedAppointment(null);
    setPrescriptionNote('');
  };

  const handleSubmitPrescription = async () => {
    try {
      await axios.post(`http://localhost:5000/api/prescriptions`, {
        appointmentId: selectedAppointment.id,
        doctorId: user.id,
        patientId: selectedAppointment.patientId,
        notes: prescriptionNote,
      });
      await handleUpdateAppointment(selectedAppointment.id, 'completed');
      handleClosePrescription();
      fetchDashboardData();
    } catch (error) {
      console.error('Error submitting prescription:', error);
    }
  };

  const handleUpdateAppointment = async (appointmentId, status) => {
    try {
      await axios.put(`http://localhost:5000/api/appointments/${appointmentId}/status`, {
        status,
      });
      fetchDashboardData();
    } catch (error) {
      console.error('Error updating appointment:', error);
    }
  };

  const getStatusColor = (status) => {
    switch (status) {
      case 'pending':
        return 'warning';
      case 'completed':
        return 'success';
      case 'cancelled':
        return 'error';
      default:
        return 'default';
    }
  };

  const filterAppointments = () => {
    const today = new Date().toISOString().split('T')[0];
    switch (activeTab) {
      case 0: // Today's appointments
        return appointments.filter(apt => apt.date.startsWith(today));
      case 1: // Upcoming appointments
        return appointments.filter(apt => 
          apt.status === 'pending' && apt.date >= today
        );
      case 2: // Past appointments
        return appointments.filter(apt => 
          apt.status === 'completed' || apt.date < today
        );
      default:
        return appointments;
    }
  };

  const StatCard = ({ icon: Icon, title, value, color }) => (
    <Card>
      <CardContent>
        <Box display="flex" alignItems="center" mb={2}>
          <Icon sx={{ fontSize: 40, color }} />
          <Typography variant="h6" ml={2} color="text.secondary">
            {title}
          </Typography>
        </Box>
        <Typography variant="h4" component="div">
          {value}
        </Typography>
      </CardContent>
    </Card>
  );

  if (loading) {
    return (
      <Container maxWidth="lg">
        <Typography>Loading...</Typography>
      </Container>
    );
  }

  return (
    <Container maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
      <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 4 }}>
        <Typography variant="h4" component="h1">
          Welcome Dr. {user?.name}
        </Typography>
        <Box>
          <Chip
            icon={<LocalHospital />}
            label={user?.department?.name || 'General'}
            color="primary"
            sx={{ mr: 1 }}
          />
          <Chip
            icon={<Person />}
            label="Doctor"
            color="secondary"
          />
        </Box>
      </Box>

      {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}
      {success && <Alert severity="success" sx={{ mb: 2 }}>{success}</Alert>}

      <Grid container spacing={3} mb={4}>
        <Grid item xs={12} sm={6} md={3}>
          <StatCard
            icon={CalendarToday}
            title="Today's Appointments"
            value={stats.todayAppointments}
            color="primary.main"
          />
        </Grid>
        <Grid item xs={12} sm={6} md={3}>
          <StatCard
            icon={AccessTime}
            title="Pending"
            value={stats.pendingAppointments}
            color="warning.main"
          />
        </Grid>
        <Grid item xs={12} sm={6} md={3}>
          <StatCard
            icon={CheckCircleIcon}
            title="Completed"
            value={stats.completedAppointments}
            color="success.main"
          />
        </Grid>
        <Grid item xs={12} sm={6} md={3}>
          <StatCard
            icon={Assignment}
            title="Total Patients"
            value={stats.totalPatients}
            color="info.main"
          />
        </Grid>
      </Grid>

      <Paper sx={{ p: 3 }}>
        <Box sx={{ borderBottom: 1, borderColor: 'divider', mb: 2 }}>
          <Tabs value={activeTab} onChange={handleTabChange}>
            <Tab label="Today's Appointments" />
            <Tab label="Upcoming Appointments" />
            <Tab label="Past Appointments" />
          </Tabs>
        </Box>

        <TableContainer>
          <Table>
            <TableHead>
              <TableRow>
                <TableCell>Patient</TableCell>
                <TableCell>Date & Time</TableCell>
                <TableCell>Type</TableCell>
                <TableCell>Symptoms</TableCell>
                <TableCell>Status</TableCell>
                <TableCell align="center">Actions</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {filterAppointments().map((appointment) => (
                <TableRow key={appointment._id}>
                  <TableCell>
                    <Box sx={{ display: 'flex', alignItems: 'center' }}>
                      <Avatar sx={{ mr: 2 }}>{appointment.patient?.name?.[0]}</Avatar>
                      <Box>
                        <Typography variant="subtitle2">
                          {appointment.patient?.name}
                        </Typography>
                        <Typography variant="body2" color="textSecondary">
                          ID: {appointment.patient?._id}
                        </Typography>
                      </Box>
                    </Box>
                  </TableCell>
                  <TableCell>
                    <Typography variant="subtitle2">
                      {format(new Date(appointment.date), 'MMM dd, yyyy')}
                    </Typography>
                    <Typography variant="body2" color="textSecondary">
                      {appointment.time}
                    </Typography>
                  </TableCell>
                  <TableCell>{appointment.type}</TableCell>
                  <TableCell>{appointment.symptoms}</TableCell>
                  <TableCell>
                    <Chip
                      label={appointment.status}
                      color={getStatusColor(appointment.status)}
                      size="small"
                    />
                  </TableCell>
                  <TableCell align="center">
                    {appointment.status === 'pending' && (
                      <Box>
                        <Tooltip title="Complete & Add Prescription">
                          <IconButton
                            color="primary"
                            onClick={() => handleOpenPrescription(appointment)}
                          >
                            <Edit />
                          </IconButton>
                        </Tooltip>
                        <Tooltip title="Cancel Appointment">
                          <IconButton
                            color="error"
                            onClick={() => handleUpdateAppointment(appointment._id, 'cancelled')}
                          >
                            <CancelIcon />
                          </IconButton>
                        </Tooltip>
                      </Box>
                    )}
                    {appointment.status === 'completed' && (
                      <Tooltip title="View Prescription">
                        <IconButton
                          color="primary"
                          onClick={() => handleOpenPrescription(appointment)}
                        >
                          <Assignment />
                        </IconButton>
                      </Tooltip>
                    )}
                  </TableCell>
                </TableRow>
              ))}
              {filterAppointments().length === 0 && (
                <TableRow>
                  <TableCell colSpan={6} align="center">
                    <Typography variant="subtitle1" color="textSecondary">
                      No appointments found
                    </Typography>
                  </TableCell>
                </TableRow>
              )}
            </TableBody>
          </Table>
        </TableContainer>
      </Paper>

      <Dialog
        open={openPrescriptionDialog}
        onClose={handleClosePrescription}
        maxWidth="md"
        fullWidth
      >
        <DialogTitle>
          <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <Typography variant="h6">
              {selectedAppointment?.status === 'completed' 
                ? 'View Prescription' 
                : 'Add Prescription'}
            </Typography>
            <IconButton onClick={handleClosePrescription}>
              <CloseIcon />
            </IconButton>
          </Box>
        </DialogTitle>
        <DialogContent>
          {selectedAppointment && (
            <Box sx={{ mt: 2 }}>
              <Grid container spacing={2}>
                <Grid item xs={12}>
                  <TextField
                    fullWidth
                    multiline
                    rows={4}
                    label="Prescription Notes"
                    value={prescriptionNote}
                    onChange={(e) => setPrescriptionNote(e.target.value)}
                    disabled={selectedAppointment.status === 'completed'}
                  />
                </Grid>
              </Grid>
            </Box>
          )}
        </DialogContent>
        <DialogActions>
          <Button onClick={handleClosePrescription}>Cancel</Button>
          {selectedAppointment?.status !== 'completed' && (
            <Button
              onClick={handleSubmitPrescription}
              variant="contained"
              disabled={!prescriptionNote.trim()}
            >
              Submit & Complete Appointment
            </Button>
          )}
        </DialogActions>
      </Dialog>
    </Container>
  );
};

export default Dashboard;
